```python
        try:
            bs_cmd = self.get_finalized_command('build_scripts')
        except ImportError:
            bs_cmd = None
        exec_param = getattr(bs_cmd, 'executable', None)
        try:
            bw_cmd = self.get_finalized_command("bdist_wininst")
        except ImportError:
            bw_cmd = None
