@robertnishihara I've been able to successfully reproduce this memory leak in the nightly builds of both Python 2.7 and Python 3.6. Here is a slightly more compact script (though it still might take a little bit of time to show the memory leak so please be patient with it), that is able to cause the memory leak in Python 3.6.

```
import ray

@ray.remote
def calculate_sum(obj_list, idx_start, idx_end):
    current_sum = 0.0
    for i in range(idx_start, idx_end):
        obj = obj_list[i]
        for key in obj:
            current_sum += obj[key]

    return current_sum

def calculate_sum_distributed(obj_list, num_ray_tasks=10):
    obj_list_id = ray.put(obj_list)

    ray_tasks = []

    start_idx = 0
    idx_delta = len(obj_list) // num_ray_tasks
    for task_num in range(num_ray_tasks):
        if task_num == num_ray_tasks - 1:
            # last task
            end_idx = len(obj_list)
        else:
            end_idx = start_idx + idx_delta

        # each task calculates the sum of a segment of the list
        task_id = calculate_sum.remote(obj_list_id, start_idx, end_idx)
        ray_tasks.append(task_id)
        start_idx = end_idx

    return sum(ray.get(ray_tasks))


if __name__ == "__main__":
    ray.init()

    obj_list = []
    for _ in range(100000):
        obj = {}
        for i in range(100):
            obj[i] = i
        obj_list.append(obj)

    for i in range(0, 1000):
        print(i)
        print(calculate_sum_distributed(obj_list))
```

